// Ambil semua data dari Google Sheets
const rows = $input.all().map(i => i.json);

// Tentukan bulan laporan
const now = new Date();
let bln = now.getMonth() - 1;
let thn = now.getFullYear();
if (bln < 0) {
  bln = 11;
  thn--;
}

// Filter data bulan terpilih
const filteredRows = rows.filter(r => {
  const d = new Date(r.Tanggal); // ambil tanggal
  if (isNaN(d)) return false; // cek data valid

  // Ambil bulan dan tahun
  return (
    d.getMonth() === bln &&
    d.getFullYear() === thn
  );
});

if (!filteredRows.length) {
  throw new Error(
    `Tidak ada data untuk bulan ${bln + 1}/${thn}`
  );
}

// Helper untuk hasil bulan (ex. Mei 2026)
const bulan = new Date(thn, bln, 1).toLocaleDateString('id-ID', {
  month: 'long',
  year: 'numeric'
});

const rp = n => 'Rp ' + Number(n).toLocaleString('id-ID'); // format rupiah

// Agregasi
let totalIn = 0;
let totalOut = 0;
const divisiOut = {};

// loop data yang sudah di filter
for (const r of filteredRows) {
  // Mengubah nominal menjadi angka
  const nominal = parseFloat(
    String(r.Nominal).replace(/[^0-9.]/g, '')
  ) || 0;

  if (r.Jenis === 'Pemasukan') { // Menambah total Pemasukan
    totalIn += nominal;
  } else { // Menambah total pengeluaran
    totalOut += nominal;

    // Pengeluaran per divisi
    const divisi = r.Divisi || 'Umum';
    divisiOut[divisi] =
      (divisiOut[divisi] || 0) + nominal;
  }
}

// Perhitungan KPI
const saldo = totalIn - totalOut; // saldo akhir
const rasioPengeluaran = totalIn > 0 ? ( // rasio pengeluaran
  (totalOut / totalIn) * 100
).toFixed(1) : '0.0';

const divisiOutSorted = Object.entries(divisiOut)
  .sort((a, b) => b[1] - a[1]); // urutkan divisi

const divisiPalingBoros = divisiOutSorted[0]?.[0] || 'N/A'; // divisi boros
const nominalBoros = divisiOutSorted[0]?.[1] || 0; // nominal borosnya
const persenBoros = totalOut > 0 ? ( // persenan boros
  (nominalBoros / totalOut) * 100
).toFixed(1) : '0.0';

// Data Chart PDF
const chartDataDivisi = divisiOutSorted.slice(0, 6)
  .map(([label, value]) => ({
    label,
    value,
    persen: totalOut > 0 ? Math.round(
      (value / totalOut) * 100
    ) : 0
  }));

// Tabel Ringkasan untuk AI
const tabelDivisi =
`| Divisi | Pengeluaran |
|---------|------------|` +
'\n' +
divisiOutSorted.map(([div, val]) => // mapping pengeluaran perdivisi
    `| ${div} | ${rp(val)} |`
  ).join('\n');

// Ringkasan untuk AI CFO
const tabelMarkdown = `
## Ringkasan Cashflow ${bulan}

### KPI
- Total Pemasukan: ${rp(totalIn)}
- Total Pengeluaran: ${rp(totalOut)}
- Saldo Bersih: ${rp(saldo)}
- Rasio Pengeluaran: ${rasioPengeluaran}%

### Divisi Pengeluaran
${tabelDivisi}

### Temuan Awal
- Divisi paling boros: ${divisiPalingBoros}
- Nominal: ${rp(nominalBoros)}
- Kontribusi terhadap total pengeluaran: ${persenBoros}%
`.trim();

// Output
return [{
  json: {
    bulan,
    totalPemasukan: totalIn,
    totalPengeluaran: totalOut,
    saldo,

    rasioPengeluaran: parseFloat(rasioPengeluaran),
    divisiPalingBoros,
    persenBoros: parseFloat(persenBoros),
    divisiOutSorted,

    chartDataDivisi,
    tabelMarkdown
  }
}];

